#include <iostream>
using namespace std;

int main() {
    // 1. Створення єдиної змінної на Купі та ініціалізація значенням 42
    int* dataPointer = new int(42); 
    cout << "Значення на купі: " << *dataPointer << endl;

    // Ручне звільнення пам'яті
    delete dataPointer;
    dataPointer = nullptr; // Запобігаємо Dangling Pointer

    // 2. Створення великого масиву. 
    // Розмір динамічного масиву можна задавати змінною (на Stack це заборонено!)
    int size;
    cout << "Введіть розмір масиву: ";
    cin >> size;

    // Виділяємо пам'ять
    int* dynamicArr = new int[size];

    // Працюємо як зі звичайним масивом
    for (int i = 0; i < size; i++) {
        dynamicArr[i] = (i + 1) * 10; 
    }

    cout << "Перший і останній елемент: " 
         << dynamicArr[0] << " ... " << dynamicArr[size - 1] << endl;

    // 3. Звільнення пам'яті масиву. Обов'язково []
    delete[] dynamicArr;
    dynamicArr = nullptr;

    return 0;
}
